  ('social-worker-moex-03520', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '個體從出生後，受各式因素的影響開始逐步出現不同的生理行為，請依據該行為出現的年齡（由 小而大）進行排序：', '["咕咕聲→比手畫腳→哭聲", "哭聲→喃喃發聲→比手畫腳", "喃喃發聲→比手畫腳→咕咕聲", "比手畫腳→咕咕聲→喃喃發聲"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "4219c64d0f26", "answer_pdf_sha1": "b0314e63bbd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03521', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '對於生理老化的學說，大體可以區分成遺傳因素（geneticprogram）和破壞因素（stochasticorrandom damage）兩大類，下列那些學說屬於破壞因素類理論？', '["剝奪理論、細胞耗竭理論", "老化錯誤理論、耗損理論", "老化錯誤理論、免疫理論", "堆積理論、自由基理論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "4219c64d0f26", "answer_pdf_sha1": "b0314e63bbd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03522', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '根據Curtis及Schuler（2004）的研究發現，下列有關胎兒發展里程碑的說明，何者錯誤？', '["手臂和腿從懷孕後第一個月起開始長出", "指紋的建立是在懷孕後第五個月", "懷孕後第二個月可偵測到胎兒的心跳", "骨骼從懷孕後第三個月開始發育"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "4219c64d0f26", "answer_pdf_sha1": "b0314e63bbd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 22, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03523', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何者不屬於Brim（1975）和Bronfenbrenner（1977）所指社會系統的四個類型或層次？', '["微視系統（microsystems）", "次級系統（subsystems）", "外部系統（exosystems）", "鉅視系統（macrosystems）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "4219c64d0f26", "answer_pdf_sha1": "b0314e63bbd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03524', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關E.Erikson心理社會發展論的人生發展階段，下列何者正確？', '["2至3歲：自主vs.羞愧懷疑", "3至6歲：勤奮進取vs.自卑自貶", "11至18歲：親密vs.孤獨疏離", "35至65歲：完美無憾vs.悲觀絕望"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "4219c64d0f26", "answer_pdf_sha1": "b0314e63bbd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03525', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '透過與情境交互作用所產生的經驗，與個人生命經驗有密切關係，並將知識和技巧融入思考與行 動過程，且至成年期後持續累積，逐漸增加，上述係屬於Cattell所稱的何種智力？', '["晶質智力（crystallizedintelligence）", "流質智力（fluidintelligence）", "組合性智力（componentialintelligence）", "經驗性智力（experientialintelligence）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "4219c64d0f26", "answer_pdf_sha1": "b0314e63bbd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03526', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '兒童開始辨別性別類型的遊戲，且發展出性別穩定的概念，學習性別刻板印象的行為，但對於性 別取向行為比較僵化，此為那一個時期的發展階段？', '["學齡前期", "學齡期", "青少年期", "嬰幼兒期"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "4219c64d0f26", "answer_pdf_sha1": "b0314e63bbd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03527', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '某甲有偷竊的行為，進一步了解其交友情形，發現其朋友可能也都有著為了生存而偷竊的偏差行 為，思考某甲可能是在跟他們的互動中，學習到合理化這些偏差行為。上述推論最可能是基於下 列何種理論的解釋？', '["功能論", "衝突理論", "系統理論", "社會學習理論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "4219c64d0f26", "answer_pdf_sha1": "b0314e63bbd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03528', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「兒童對於學習數學有些負面情緒，每次小考考不好，就覺得自己的數學能力不好、怎麼認真也 沒用，而當考得不錯時，也認為這應該是運氣好、不是自己努力而來的。」這樣的敘述最符合下 列那項概念？', '["學習無用論", "社會學習論", "習得無助感", "社會交換論"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "4219c64d0f26", "answer_pdf_sha1": "b0314e63bbd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03529', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依據美國焦慮症協會（AnxietyDisordersAssociation）的報告，有關兒童可能經歷之焦慮問題，下 列敘述何者錯誤？', '["社交焦慮：遇見陌生人會焦慮", "分離焦慮：害怕離開照顧者", "恐慌症：無預期且重複的恐慌症狀", "過動症：注意力不集中，易衝動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:19+00:00", "source_pdf_sha1": "4219c64d0f26", "answer_pdf_sha1": "b0314e63bbd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
